{"file_path":"/home/user/workspace/lib/posts.ts","content":"import { unstable_cache } from 'next/cache';
import { getPostsFromDb } from './data';
import type { Post } from './types';

/**
 * Fetch all posts, cached under the "posts" tag.
 *
 * The cached result is tied to the `["posts-all"]` key and tagged with
 * `["posts"]`. Calling `revalidateTag("posts")` from a Server Action
 * purges this cache entry so the next request re-executes the function
 * and returns fresh data.
 */
export const getPosts = unstable_cache(
  async (): Promise<Post[]> => getPostsFromDb(),
  ['posts-all'],
  { tags: ['posts'] },
);
"}

