{"file_path":"/home/user/workspace/lib/actions.ts","content":"'use server';

import { revalidateTag } from 'next/cache';
import { insertPost } from './data';

export type CreatePostState = {
  error?: string;
  success: boolean;
};

export async function createPost(
  _prevState: CreatePostState,
  formData: FormData,
): Promise<CreatePostState> {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || typeof title !== 'string' || title.trim().length === 0) {
    return { error: 'Title is required.', success: false };
  }
  if (
    !content ||
    typeof content !== 'string' ||
    content.trim().length === 0
  ) {
    return { error: 'Content is required.', success: false };
  }

  await insertPost(title.trim(), content.trim());

  // ───────────────────────────────────────────────────────────────
  // Invalidate every cache entry tagged with "posts".
  //
  // This purges the server-side data cache that `getPosts` (via
  // `unstable_cache`) relies on.  The NEXT request to the Server
  // Component that calls `getPosts` will re-execute the function
  // and serve freshly-fetched data — stale content is never handed
  // to the client.
  // ───────────────────────────────────────────────────────────────
  revalidateTag('posts');

  return { success: true };
}
"}

