{"file_path":"/home/user/workspace/components/create-post-form.tsx","content":"'use client';

import { useActionState } from 'react';
import { createPost, type CreatePostState } from '@/lib/actions';

const initialState: CreatePostState = { success: false };

export function CreatePostForm() {
  const [state, formAction, pending] = useActionState(
    createPost,
    initialState,
  );

  return (
    <form action={formAction}>
      <fieldset disabled={pending}>
        <div>
          <label htmlFor="title">Title</label>
          <input id="title" name="title" type="text" required />
        </div>

        <div>
          <label htmlFor="content">Content</label>
          <textarea id="content" name="content" rows={4} required />
        </div>

        <button type="submit">{pending ? 'Creating…' : 'Create Post'}</button>

        {state.error && <p style={{ color: 'red' }}>{state.error}</p>}
        {state.success && (
          <p style={{ color: 'green' }}>Post created successfully!</p>
        )}
      </fieldset>
    </form>
  );
}
"}

